void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<int>(n + 1);
	var b = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	fa(i, 1, n)cin >> b[i];
	sort(all1(a)), sort(all1(b));
	var da = deque<int>();
	var db = deque<int>();
	fa(i, 1, n)da.pb(a[i]), db.pb(b[i]);
	int ans = 0;
	while (da.size() and db.size()) {
		if (da.back() > db.back()) {
			ans++;
			da.pop_back();
			db.pop_back();
		}
		else if (da.front() > db.front()) {
			ans++;
			da.pop_front();
			db.pop_front();
		}
		else {
			if (da.front() != db.back())ans--; // 考虑相等的情况
			da.pop_front();
			db.pop_back();
		}
	}
	cout << ans * 200 << endl;
	return;
}
